export const localizeIdiom = (idiom, t) => {
  if (!idiom || !t) return idiom;
  const keys = IDIOM_I18N_KEYS[idiom.hanja];
  if (!keys) return idiom;
  return {
    ...idiom,
    meaning: keys.meaning ? t(keys.meaning) : idiom.meaning,
    origin: keys.origin ? t(keys.origin) : idiom.origin,
  };
};

export const localizeIdioms = (idioms, t) => (
  t ? idioms.map((idiom) => localizeIdiom(idiom, t)) : idioms
);
